// Dictionary entry for pronunciation/replacement
export interface DictionaryEntry {
  id: string;
  term: string; // What to look for (e.g., "COMEX", "$", "oz")
  replacement: string; // What to say instead (e.g., "Coe-Mex", "dollars", "ounces")
  enabled: boolean;
}

// Pattern handler state (just name and enabled)
export interface PatternState {
  name: string;
  enabled: boolean;
}

export interface ConfigData {
  dictionary: DictionaryEntry[];
  patterns: PatternState[];
  apiKeys: Record<string, string>;
  // Future: security settings, etc.
}

