function buildIntentStarterSettings(
  presetId: IntentStarterPresetId,
  agentIds: string[],
): IntentSettings {
  const preset = INTENT_STARTER_PRESETS[presetId];
  const uniqueAgentIds = uniqueNonEmptyStrings(agentIds);
  const resolvedAgentIds = uniqueAgentIds.length > 0 ? uniqueAgentIds : ["main"];
  const departments: Record<string, unknown> = {};
  const agents: Record<string, unknown> = {};

  for (const agentId of resolvedAgentIds) {
    const departmentId = inferIntentDepartmentId(agentId);
    if (!departments[departmentId]) {
      departments[departmentId] = buildStarterDepartmentPolicy(departmentId);
    }
    agents[agentId] = {
      version: "1.0.0",
      owner: "ArgentOS Intent Bootstrap",
      departmentId,
      role: inferIntentRole(agentId),
      requireAcknowledgmentBeforeClose: true,
      usePersistentHistory: true,
      weightPreviousEscalations: true,
    };
  }

  return {
    enabled: true,
    validationMode: preset.validationMode,
    runtimeMode: preset.runtimeMode,
    global: {
      version: "1.0.0",
      owner: "Jason / ArgentOS Core",
      objective: "Align every agent action to long-term operator and organizational outcomes.",
      coreValues: [
        "customer_retention_over_short_term_efficiency",
        "accuracy_over_speed",
        "escalate_over_bad_resolution",
        "human_dignity_in_every_interaction",
      ],
      tradeoffHierarchy: [
        "long_term_relationship_value",
        "accuracy_and_trust",
        "resolution_quality",
        "resolution_speed",
        "operational_efficiency",
      ],
      neverDo: [
        "close_interaction_without_acknowledgment",
        "make_commitments_outside_authorized_scope",
        "share_sensitive_data_outside_policy",
      ],
      allowedActions: [
        "resolve_known_pattern",
        "request_missing_context",
        "prepare_handoff_packet",
        "update_task_state_with_evidence",
      ],
      requiresHumanApproval: [
        "policy_exception",
        "financial_commitment",
        "account_closure",
        "legal_or_pr_risk",
      ],
      requireAcknowledgmentBeforeClose: true,
      usePersistentHistory: true,
      weightPreviousEscalations: true,
      escalation: {
        sentimentThreshold: -0.35,
        maxAttemptsBeforeEscalation: 2,
        timeInConversationMinutes: 10,
        customerTiersAlwaysEscalate: ["enterprise", "vip"],
      },
    },
    departments,
    agents,
    simulationGate: {
      enabled: preset.simulationGate.enabled,
      mode: preset.simulationGate.mode,
      minPassRate: preset.simulationGate.minPassRate,
      suites: [],
      reportPath: "reports/intent/simulation-latest.json",
    },
  };
}

function uniqueNonEmptyStrings(values: string[]): string[] {
  const out: string[] = [];
  const seen = new Set<string>();
  for (const raw of values) {
    const value = raw.trim();
    if (!value || seen.has(value)) continue;
    seen.add(value);
    out.push(value);
  }
  return out;
}

function parseMultilineList(value: string): string[] {
  return uniqueNonEmptyStrings(value.split("\n"));
}

function formatMultilineList(values?: string[]): string {
  return Array.isArray(values) ? values.join("\n") : "";
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return Boolean(value) && typeof value === "object" && !Array.isArray(value);
}

function readString(value: unknown, fallback = ""): string {
  return typeof value === "string" ? value : fallback;
}

function readStringList(value: unknown): string[] {
  if (!Array.isArray(value)) return [];
  return uniqueNonEmptyStrings(value.map((entry) => String(entry)));
}

function readBoolean(value: unknown, fallback = false): boolean {
  return typeof value === "boolean" ? value : fallback;
}

function readPositiveInteger(value: unknown, fallback: number): number {
  if (typeof value !== "number" || !Number.isFinite(value)) return fallback;
  return Math.max(1, Math.floor(value));
}

function readBoundedNumber(value: unknown, fallback: number, min: number, max: number): number {
  if (typeof value !== "number" || !Number.isFinite(value)) return fallback;
  return Math.max(min, Math.min(max, value));
}

type IntentPolicyEditorDraft = {
  version: string;
  owner: string;
  objective: string;
  tradeoffHierarchy: string[];
  neverDo: string[];
  allowedActions: string[];
  requiresHumanApproval: string[];
  requireAcknowledgmentBeforeClose: boolean;
  usePersistentHistory: boolean;
  weightPreviousEscalations: boolean;
  escalation: IntentEscalationSettings;
  departmentId?: string;
  role?: string;
  parentGlobalVersion?: string;
  parentDepartmentVersion?: string;
};

function normalizeIntentPolicyEditorDraft(value: unknown): IntentPolicyEditorDraft {
  const record = isRecord(value) ? value : {};
  const escalation = isRecord(record.escalation) ? record.escalation : {};
  const departmentId = readString(record.departmentId).trim();
  const role = readString(record.role).trim();
  const parentGlobalVersion = readString(record.parentGlobalVersion).trim();
  const parentDepartmentVersion = readString(record.parentDepartmentVersion).trim();
  return {
    version: readString(record.version).trim(),
    owner: readString(record.owner).trim(),
    objective: readString(record.objective).trim(),
    tradeoffHierarchy: readStringList(record.tradeoffHierarchy),
    neverDo: readStringList(record.neverDo),
    allowedActions: readStringList(record.allowedActions),
    requiresHumanApproval: readStringList(record.requiresHumanApproval),
    requireAcknowledgmentBeforeClose: readBoolean(record.requireAcknowledgmentBeforeClose, false),
    usePersistentHistory: readBoolean(record.usePersistentHistory, false),
    weightPreviousEscalations: readBoolean(record.weightPreviousEscalations, false),
    escalation: {
      sentimentThreshold: readBoundedNumber(escalation.sentimentThreshold, -0.35, -1, 1),
      maxAttemptsBeforeEscalation: readPositiveInteger(escalation.maxAttemptsBeforeEscalation, 2),
      timeInConversationMinutes: readPositiveInteger(escalation.timeInConversationMinutes, 10),
      customerTiersAlwaysEscalate: readStringList(escalation.customerTiersAlwaysEscalate),
    },
    departmentId: departmentId || undefined,
    role: role || undefined,
    parentGlobalVersion: parentGlobalVersion || undefined,
    parentDepartmentVersion: parentDepartmentVersion || undefined,
  };
}

function intentPolicyEditorDraftToRecord(
  draft: IntentPolicyEditorDraft,
  options?: { includeAgentFields?: boolean },
): Record<string, unknown> {
  const record: Record<string, unknown> = {
    requireAcknowledgmentBeforeClose: draft.requireAcknowledgmentBeforeClose,
    usePersistentHistory: draft.usePersistentHistory,
    weightPreviousEscalations: draft.weightPreviousEscalations,
    escalation: {
      sentimentThreshold: Math.max(-1, Math.min(1, draft.escalation.sentimentThreshold)),
      maxAttemptsBeforeEscalation: Math.max(
        1,
        Math.floor(draft.escalation.maxAttemptsBeforeEscalation),
      ),
      timeInConversationMinutes: Math.max(
        1,
        Math.floor(draft.escalation.timeInConversationMinutes),
      ),
      customerTiersAlwaysEscalate: uniqueNonEmptyStrings(
        draft.escalation.customerTiersAlwaysEscalate || [],
      ),
    },
  };
  if (draft.version) record.version = draft.version;
  if (draft.owner) record.owner = draft.owner;
  if (draft.objective) record.objective = draft.objective;
  const tradeoffHierarchy = uniqueNonEmptyStrings(draft.tradeoffHierarchy || []);
  const neverDo = uniqueNonEmptyStrings(draft.neverDo || []);
  const allowedActions = uniqueNonEmptyStrings(draft.allowedActions || []);
  const requiresHumanApproval = uniqueNonEmptyStrings(draft.requiresHumanApproval || []);
  if (tradeoffHierarchy.length > 0) record.tradeoffHierarchy = tradeoffHierarchy;
  if (neverDo.length > 0) record.neverDo = neverDo;
  if (allowedActions.length > 0) record.allowedActions = allowedActions;
  if (requiresHumanApproval.length > 0) record.requiresHumanApproval = requiresHumanApproval;
  const escalationRecord = record.escalation as Record<string, unknown>;
  if (!escalationRecord.customerTiersAlwaysEscalate) {
    delete escalationRecord.customerTiersAlwaysEscalate;
  }
  if (options?.includeAgentFields) {
    if (draft.departmentId) record.departmentId = draft.departmentId;
    if (draft.role) record.role = draft.role;
    if (draft.parentGlobalVersion) record.parentGlobalVersion = draft.parentGlobalVersion;
    if (draft.parentDepartmentVersion) {
      record.parentDepartmentVersion = draft.parentDepartmentVersion;
    }
  }
  return record;
}

function safeParseIntentMapJson(value: string): {
  value: Record<string, unknown>;
  error: string | null;
} {
  try {
    const parsed = JSON.parse(value || "{}");
    if (!isRecord(parsed)) {
      return { value: {}, error: "Expected a JSON object." };
    }
    return { value: parsed, error: null };
  } catch (err) {
    return { value: {}, error: err instanceof Error ? err.message : "Parse failed." };
  }
}

function nextAvailableIntentMapKey(map: Record<string, unknown>, base: string): string {
  const normalizedBase = base.trim() || "item";
  if (!Object.hasOwn(map, normalizedBase)) return normalizedBase;
  let index = 2;
  while (Object.hasOwn(map, `${normalizedBase}-${index}`)) {
    index += 1;
  }
  return `${normalizedBase}-${index}`;
}

function loadConfig(): ConfigData {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    if (stored) {
      return { ...defaultConfig, ...JSON.parse(stored) };
    }
  } catch (e) {
    console.error("[Config] Failed to load:", e);
  }
  return defaultConfig;
}

function saveConfig(config: ConfigData) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(config));
  } catch (e) {
    console.error("[Config] Failed to save:", e);
  }
}

