function formatTimeRemaining(timestampMs: number): string {
  const remaining = timestampMs - Date.now();
  if (remaining <= 0) return "Ready";

  const hours = Math.floor(remaining / (1000 * 60 * 60));
  const minutes = Math.floor((remaining % (1000 * 60 * 60)) / (1000 * 60));

  if (hours > 0) {
    return `${hours}h ${minutes}m`;
  }
  return `${minutes}m`;
}

function formatCooldownExpiry(timestampMs: number): string {
  const date = new Date(timestampMs);
  const now = new Date();
  const isToday = date.toDateString() === now.toDateString();
  const tomorrow = new Date(now);
  tomorrow.setDate(tomorrow.getDate() + 1);
  const isTomorrow = date.toDateString() === tomorrow.toDateString();

  const timeStr = date.toLocaleTimeString("en-US", { hour: "numeric", minute: "2-digit" });

  if (isToday) return `Today at ${timeStr}`;
  if (isTomorrow) return `Tomorrow at ${timeStr}`;
  return `${date.toLocaleDateString("en-US", { weekday: "short", month: "short", day: "numeric" })} at ${timeStr}`;
}

function formatExecutionWorkerSkipReason(reason: string): string {
  switch (reason) {
    case "not-started":
      return "not started";
    case "no-runnable-tasks":
      return "no runnable tasks";
    case "agent-busy":
      return "agent busy";
    case "cycle-error":
      return "cycle error";
    default:
      return reason.replaceAll("-", " ");
  }
}

type FetchJsonRetryOptions = {
  signal?: AbortSignal;
  timeoutMs?: number;
  retries?: number;
  retryDelayMs?: number;
};

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

function isAbortError(error: unknown): boolean {
  return !!error && typeof error === "object" && (error as { name?: string }).name === "AbortError";
}

async function fetchJsonWithRetry<T = unknown>(
  url: string,
  options: FetchJsonRetryOptions = {},
): Promise<T> {
  const timeoutMs =
    typeof options.timeoutMs === "number" &&
    Number.isFinite(options.timeoutMs) &&
    options.timeoutMs > 0
      ? options.timeoutMs
      : 20000;
  const retries = Math.max(0, options.retries ?? 1);
  const retryDelayMs = Math.max(0, options.retryDelayMs ?? 350);
  let lastError: unknown;

  for (let attempt = 0; attempt <= retries; attempt += 1) {
    const controller = new AbortController();
    const externalSignal = options.signal;
    const onAbort = () => controller.abort();
    if (externalSignal?.aborted) {
      controller.abort();
    } else if (externalSignal) {
      externalSignal.addEventListener("abort", onAbort, { once: true });
    }
    const timeout = timeoutMs > 0 ? setTimeout(() => controller.abort(), timeoutMs) : null;
    try {
      const response = await fetch(url, { signal: controller.signal });
      if (!response.ok) {
        throw new Error(`HTTP ${response.status} for ${url}`);
      }
      return (await response.json()) as T;
    } catch (error) {
      lastError = error;
      if (externalSignal?.aborted || attempt >= retries) {
        throw error;
      }
      await sleep(retryDelayMs * (attempt + 1));
    } finally {
      if (timeout) {
        clearTimeout(timeout);
      }
      if (externalSignal) {
        externalSignal.removeEventListener("abort", onAbort);
      }
    }
  }
  throw lastError ?? new Error(`Failed to fetch ${url}`);
}

