  const runVaultIngest = async (dryRun: boolean) => {
    if (!gatewayRequest) {
      setMemoryV3Message({
        type: "error",
        text: "Gateway request function unavailable; cannot run vault ingest from the dashboard.",
      });
      return;
    }
    try {
      setVaultIngestAction(dryRun ? "preview" : "run");
      setMemoryV3Message(null);
      const result = (await gatewayRequest("knowledge.vault.ingest", {
        options: { dryRun, limitFiles: 250 },
      })) as Record<string, any>;
      if (dryRun) {
        setMemoryV3Message({
          type: "success",
          text: `Vault preview found ${result?.count || 0} markdown files under ${String(result?.rootPath || "configured vault")}.`,
        });
      } else {
        setMemoryV3Message({
          type: "success",
          text: `Vault ingest completed: ${result?.acceptedFiles || 0} file(s), ${result?.totalChunks || 0} chunk(s), ${result?.embeddedChunks || 0} embedded chunk(s) into ${String(result?.collection || "vault-knowledge")}.`,
        });
      }
      void loadMemoryV3Status();
    } catch (err) {
      setMemoryV3Message({
        type: "error",
        text: err instanceof Error ? err.message : "Vault ingest failed.",
      });
    } finally {
      setVaultIngestAction(null);
    }
  };

  const bootstrapInternalVault = async (forceBind: boolean) => {
    try {
      setMemoryV3StatusAction(forceBind ? "bind" : "bootstrap");
      setMemoryV3Message(null);
      const response = await fetch("/api/settings/memory-v3/bootstrap-vault", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ forceBind }),
      });
      const payload = (await response.json().catch(() => ({}))) as {
        ok?: boolean;
        path?: string;
        boundToConfig?: boolean;
        error?: string;
        status?: MemoryV3StatusResponse;
      };
      if (!response.ok || payload.ok === false) {
        throw new Error(
          typeof payload?.error === "string"
            ? payload.error
            : `HTTP ${response.status} while bootstrapping vault`,
        );
      }
      if (payload.status) setMemoryV3Status(payload.status);
      if (payload.boundToConfig) {
        setVaultPathDraft(payload.path || "");
      }
      setMemoryV3Message({
        type: "success",
        text: payload.boundToConfig
          ? `Created and bound Argent vault at ${payload.path || "configured internal path"}.`
          : `Argent vault is ready at ${payload.path || "default internal path"}.`,
      });
      void loadMemoryV3Status();
    } catch (err) {
      setMemoryV3Message({
        type: "error",
        text: err instanceof Error ? err.message : "Failed to bootstrap internal vault.",
      });
    } finally {
      setMemoryV3StatusAction(null);
    }
  };

